const now = new Date();
const h = now.getUTCHours();
const m = now.getUTCMinutes();
const dow = now.getUTCDay();

const reminders = [
  { id:'morning_water',   cron:'0 8 * * *',   msg:'💧 Good morning, {name}! Start your day with a big glass of water. Hydration = performance.' },
  { id:'midday_checkin',  cron:'0 13 * * *',  msg:'🥗 Lunchtime! Your daily target is {daily_calorie_target} kcal. Staying on track?' },
  { id:'afternoon_work',  cron:'0 18 * * *',  msg:'🏋️ Still time for a workout! Even 20 minutes makes a difference. You got this, {name}.' },
  { id:'evening_wind',    cron:'0 21 * * *',  msg:'🌙 Wind-down time. Aim for 7–9 hours tonight. Great sleep is where progress happens.' }
];

function matches(cron, hour, min, day) {
  const [cm, ch, , , cd] = cron.split(' ');
  return (ch==='*' || parseInt(ch)===hour) && (cm==='*' || parseInt(cm)===min) && (cd==='*' || parseInt(cd)===day);
}

const due = reminders.filter(r => matches(r.cron, h, m, dow));
if (!due.length) return [{ json: { skip: true } }];
return due.map(r => ({ json: { ...r, skip: false } }));

const user = $json;
const reminder = $('Per Reminder').item.json;
const msg = reminder.msg
  .replace(/{name}/g, user.first_name || 'there')
  .replace(/{daily_calorie_target}/g, user.daily_calorie_target || 2000);
return [{ json: { telegramId: user.telegram_id, message: msg } }];
